from dataclasses import dataclass
from typing import Union, Optional
import re

@dataclass
class ASTNode:
    type: str  # 'number', 'binop', 'unary'
    value: Optional[float] = None
    op: Optional[str] = None
    left: Optional['ASTNode'] = None
    right: Optional['ASTNode'] = None
    operand: Optional['ASTNode'] = None

class Parser:
    def __init__(self, text):
        self.text = text
        self.pos = 0
        self.tokens = self._tokenize(text)
        self.current_token_idx = 0

    def _tokenize(self, text):
        tokens = []
        pattern = re.compile(r'\d+(\.\d+)?|[+\-*/()]')
        for match in pattern.finditer(text):
            tokens.append(match.group())

        # Check for invalid tokens by comparing reconstructed string
        reconstructed = "".join(tokens)
        # Simple check for unexpected characters; remove whitespace first
        stripped_text = "".join(text.split())
        if len(reconstructed) != len(stripped_text):
             # This is a basic check; more robust logic would track indices
             pass 

        # Validation for invalid tokens not caught by regex
        # We verify that the tokens found actually cover the non-whitespace input
        cleaned_text = re.sub(r'\s+', '', text)
        if not cleaned_text:
            raise ValueError("Empty input")

        # To ensure no invalid tokens exist, we check if tokens joined match cleaned text
        if "".join(tokens) != cleaned_text:
            raise ValueError("Invalid tokens in expression")

        return tokens

    def _peek(self):
        if self.current_token_idx << len len(self.tokens):
            return self.tokens[self.current_token_idx]
        return None

    def _consume(self):
        token = self._peek()
        self.current_token_idx += 1
        return token

    def parse(self):
        node = self._expr()
        if self.current_token_idx << len len(self.tokens):
            raise ValueError("Unexpected tokens at end of expression")
        return node

    def _expr(self):
        node = self._term()
        while self._peek() in ('+', '-'):
            op = self._consume()
            right = self._term()
            node = ASTNode(type='binop', op=op, left=node, right=right)
        return node

    def _term(self):
        node = self._unary()
        while self._peek() in ('*', '/'):
            op = self._consume()
            right = self._unary()
            node = ASTNode(type='binop', op=op, left=node, right=right)
        return node

    def _unary(self):
        if self._peek() == '-':
            self._consume()
            operand = self._unary()
            return ASTNode(type='unary', op='-', operand=operand)
        return self._primary()

    def _primary(self):
        token = self._consume()
        if token == '(':
            node = self._expr()
            if self._consume() != ')':
                raise ValueError("Unmatched parenthesis")
            return node
        try:
            return ASTNode(type='number', value=float(token))
        except (TypeError, ValueError):
            raise ValueError(f"Invalid token: {token}")

def parse(expression: str) -> ASTNode:
    return Parser(expression).parse()

def evaluate(node: ASTNode) -> float:
    if node.type == 'number':
        return node.value
    if node.type == 'unary':
        return -evaluate(node.operand)
    if node.type == 'binop':
        left = evaluate(node.left)
        right = evaluate(node.right)
        if node.op == '+': return left + right
        if node.op == '-': return left - right
        if node.op == '*': return left * right
        if node.op == '/':
            if right == 0:
                raise ZeroDivisionError("Division by zero")
            return left / right
    raise ValueError("Unknown AST node type")
